#include <bits/stdc++.h>
using namespace std;

int main() {
    string s;
    cin >> s;
    set<char> known_chars(s.begin(), s.end()); 
    int t;
    cin >> t;

    while (t--) {
        string word;
        cin >> word;
        bool canRead = true;

        for (char ch : word) {
            if (known_chars.find(ch) == known_chars.end()) {
                canRead = false;
                break;
            }
        }

        if (canRead) {
            cout << "Yes" << endl;
        } else {
            cout << "No" << endl;
        }
    }

    return 0;
}

