function Alphabet(tests) {
    let s = new Set(tests[0]); // Convert string S to a set for efficient character lookup
    let t = parseInt(tests[1]);
    for (let i = 2; i < t + 2; i++) {
        let word = tests[i];
        let canRead = true;
        for (let j = 0; j < word.length; j++) {
            if (!s.has(word[j])) { // Check if Jeff knows each character of the word
                canRead = false;
                break;
            }
        }
        console.log(canRead ? "Yes" : "No");
    }
}

